import { cli, Strategy } from '@jackwener/opencli/registry';

cli({
  site: 'test-hn',
  name: 'top',
  description: 'HackerNews top stories',
  domain: 'news.ycombinator.com',
  strategy: Strategy.PUBLIC,
  browser: false,
  args: [
    { name: 'limit', type: 'int', default: 5, help: 'Number of stories' },
  ],
  columns: ['rank', 'title', 'score'],
  func: async (_page, kwargs) => {
    const limit = Math.min(kwargs.limit ?? 5, 10);
    const res = await fetch('https://hacker-news.firebaseio.com/v0/topstories.json');
    const ids = await res.json();
    const items = await Promise.all(ids.slice(0, limit).map(async (id: number) => {
      const r = await fetch(`https://hacker-news.firebaseio.com/v0/item/${id}.json`);
      return r.json();
    }));
    return items.map((item: any, i: number) => ({
      rank: i + 1, title: item.title, score: item.score,
    }));
  },
});

