import { cli, Strategy } from '@jackwener/opencli/registry';

cli({
  site: 'test-wiki',
  name: 'summary',
  description: 'Wikipedia article summary',
  domain: 'en.wikipedia.org',
  strategy: Strategy.PUBLIC,
  browser: false,
  args: [
    { name: 'title', type: 'string', default: 'JavaScript', positional: true, help: 'Article title' },
  ],
  columns: ['title', 'extract'],
  func: async (_page, kwargs) => {
    const title = encodeURIComponent(kwargs.title);
    const res = await fetch(`https://en.wikipedia.org/api/rest_v1/page/summary/${title}`);
    const d = await res.json();
    return [{ title: d.title, extract: d.extract?.slice(0, 200) }];
  },
});

