import { cli, Strategy } from '@jackwener/opencli/registry';

cli({
  site: 'test-nager',
  name: 'holidays',
  description: 'US public holidays for current year',
  domain: 'date.nager.at',
  strategy: Strategy.PUBLIC,
  browser: false,
  args: [
    { name: 'limit', type: 'int', default: 5, help: 'Number of holidays' },
  ],
  columns: ['date', 'name', 'type'],
  func: async (_page, kwargs) => {
    const limit = kwargs.limit ?? 5;
    const year = new Date().getFullYear();
    const res = await fetch(`https://date.nager.at/api/v3/PublicHolidays/${year}/US`);
    const holidays = await res.json();
    return holidays.slice(0, limit).map((h: any) => ({
      date: h.date,
      name: h.name,
      type: (h.types || []).join(','),
    }));
  },
});
